import os
import csv
import json
from tensorflow.keras.preprocessing.image import ImageDataGenerator
from tensorflow.keras.applications import VGG16
from tensorflow.keras.layers import Dense, Flatten
from tensorflow.keras.models import Model
from tensorflow.keras.optimizers import Adam
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename

app = Flask(__name__)

# Set up upload folder and allowed file extensions
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'csv'}

# Load model weights from secure storage (e.g. environment variables)
MODEL_WEIGHTS = os.environ.get('MODEL_WEIGHTS')

@app.route('/train', methods=['POST'])
def train_model():
    # Validate user input
    if not request.files['data'].filename:
        return jsonify({'error': 'No file provided'}), 400

    # Securely store uploaded CSV file
    filename = secure_filename(request.files['data'].filename)
    filepath = os.path.join(UPLOAD_FOLDER, filename)

    # Load CSV data from file
    with open(filepath, 'r') as f:
        reader = csv.reader(f)
        data = list(reader)

    # Validate and preprocess data
    if not data or len(data) == 0:
        return jsonify({'error': 'Invalid data'}), 400

    # Load model architecture from secure storage (e.g. environment variables)
    model_architecture = os.environ.get('MODEL_ARCHITECTURE')

    # Create model instance and compile it
    base_model = VGG16(weights='imagenet', include_top=False, input_shape=(224, 224, 3))
    x = Flatten()(base_model.output)
    x = Dense(128, activation='relu')(x)
    outputs = Dense(len(data[0]), activation='softmax')(x)

    model = Model(inputs=base_model.input, outputs=outputs)
    model.compile(optimizer=Adam(lr=1e-5), loss='categorical_crossentropy', metrics=['accuracy'])

    # Train model on user-provided data
    train_datagen = ImageDataGenerator(rescale=1./255,
                                        shear_range=0.2,
                                        zoom_range=0.2,
                                        horizontal_flip=True)

    test_datagen = ImageDataGenerator(rescale=1./255)

    train_generator = train_datagen.flow_from_dataframe(
        data,
        directory=None,
        x_col='image_path',
        y_col='label',
        target_size=(224, 224),
        batch_size=32,
        class_mode='categorical'
    )

    test_generator = test_datagen.flow_from_dataframe(
        data,
        directory=None,
        x_col='image_path',
        y_col='label',
        target_size=(224, 224),
        batch_size=32,
        class_mode='categorical'
    )

    model.fit(train_generator, epochs=10, validation_data=test_generator)

    # Save trained model weights to secure storage (e.g. environment variables)
    model.save_weights(MODEL_WEIGHTS)

    return jsonify({'message': 'Model trained successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)